const doc = $json.body ?? $json;
let fullText = '';

function walk(node) {
  if (node == null) return;

  if (Array.isArray(node)) {
    for (const item of node) walk(item);
    return;
  }

  if (typeof node !== 'object') return;

  // Collect actual visible text
  if (typeof node.textRun?.content === 'string') {
    fullText += node.textRun.content;
  }

  if (typeof node.autoText?.content === 'string') {
    fullText += node.autoText.content;
  }

  // Recurse into everything else
  for (const [key, value] of Object.entries(node)) {
    if (key === 'textRun' || key === 'autoText') continue;
    walk(value);
  }
}

walk(doc);

// Cleanup
fullText = fullText
  .replace(/\u0007/g, '')
  .replace(/\r/g, '')
  .trim();

return [{
  json: {
    resumeText: fullText,
    user_id: $('Resume details mapping').item.json.user_id,
    resume_name: $('Resume details mapping').item.json.name,
    email: $('Resume details mapping').item.json.email,
    resume_doc_id: $('Resume details mapping').item.json.resume_doc_id,
    job_query: $('Resume details mapping').item.json.job_query,
  }
}];

return items.filter(item => {
  const query = (item.json.job_query || '').toLowerCase().trim();
  const title = (item.json.title || '').toLowerCase();
const description = (item.json.description || '').toLowerCase();

  if (!query) {
    throw new Error(`Missing job_query for job_id: ${item.json.job_id || 'unknown'}`);
  }

  const meaningfulWords = query.split(' ').filter(w => w.length > 2);
  const text = title + ' ' + description;

  // Require at least 2 meaningful words to match, or 1 if query is short
  const threshold = meaningfulWords.length >= 3 ? 2 : 1;
  const matchCount = meaningfulWords.filter(word => text.includes(word)).length;

  return matchCount >= threshold;
});

