const data = $json.output || {};
const docId = $json.id;
const user_id = $json.user_id;
const job_id = $json.job_id;

const requests = Object.entries(data)
  // ✅ Do NOT skip empty → we handle it manually
  .filter(([k, v]) => typeof v === 'string')
  .map(([key, value]) => {

    // ✅ Fallback for empty values
    if (!value || value.trim() === '') {
      value = 'N/A';
    }

    // ✅ CLEAN TEXT (remove markdown + junk)
    value = value
      .replace(/[*_`]/g, '')          // remove markdown (*, **, _)
      .replace(/^\s*[-•]\s*/gm, '')   // remove existing bullets
      .replace(/[\\/]/g, '')          // remove / and \
      .replace(/\s+/g, ' ')           // normalize spacing
      .trim();

    // ✅ HANDLE BULLETS PROPERLY
    if (key.includes('bullets')) {
      value = value
        .split('\n')
        .map(line => line.trim())
        .filter(line => line.length > 0)
        .map(line => `• ${line}`)   // add clean bullets ONCE
        .join('\n');
    }

    // ✅ Escape characters for Google Docs API
    value = value
      .replace(/\\/g, '\\\\')
      .replace(/"/g, '\\"');

    return {
      replaceAllText: {
        containsText: {
          text: `{{${key}}}`,
          matchCase: true
        },
        replaceText: value
      }
    };
  });

return [{
  json: {
    docId,
    user_id,
    job_id,
    requests
  }
}];

