parameters.jsCode:
let placeholders = $json.placeholder_schema;

// handle undefined
if (!placeholders) {
  placeholders = [];
}

// handle string (JSON from Postgres)
if (typeof placeholders === 'string') {
  try {
    placeholders = JSON.parse(placeholders);
  } catch (e) {
    placeholders = [];
  }
}

// ensure array
if (!Array.isArray(placeholders)) {
  placeholders = [];
}

const properties = {};
for (const key of placeholders) {
  properties[key] = { type: "string" };
}

const schema = {
  type: "object",
  additionalProperties: false,
  properties
};

return [{
  json: {
    user_id: $json.user_id,
    name: $json.name,
    email: $json.email,
    resume_doc_id: $json.resume_doc_id,
    template_doc_id: $json.template_doc_id,
    resume_name: $json.resume_name,
    template_name: $json.template_name,
    job_query: $json.job_query,
    placeholder_schema: placeholders,
    dynamic_schema: JSON.stringify(schema)
  }
}];

const jobItems = $input.all();

// Schema side-chain result — referenced by node name
const schemaItem = $('Extract resume placeholder schema').first().json;
const placeholder_schema = schemaItem.placeholder_schema;
const dynamic_schema = schemaItem.dynamic_schema;

return jobItems.map(item => ({
  json: {
    ...item.json,
    placeholder_schema,
    dynamic_schema
  }
}));

